and ( s.title like concat('%', #{keyword}, '%') or u.nickname like concat('%', #{keyword}, '%') )
and s.region = #{region}
and s.detail_region = #{detailRegion}
and s.status = #{status}
order by s.created_at desc limit #{size} offset #{offset}

